mapper.select:
        SELECT
            item_id AS itemId, title, sales_type, service_type,
	        local1, local2, local3, jibun_address      AS jibunAddress,
	        deposit, rent, manage_cost AS manageCost, manage_not_includes AS manageNotIncludes,
	        area_m2 AS areaM2, area_contract_m2 AS areaContractM2,
	        floor_level AS floorLevel, all_floors AS allFloors,
	        lat, lng, options,
            subway, nb_distribution AS nbDistribution, nb_amenity AS nbAmenity, nb_poi, item_image
        FROM property


                AND sales_type = #{salesType}


                AND service_type = #{serviceType}


                AND local1 = #{local1}


                AND local2 = #{local2}


                AND local3 = #{local3}


                AND deposit >= #{depositMin}


                AND deposit <= #{depositMax}


                AND rent <= #{rentMax}


                AND area_m2 >= #{areaMin}


                AND area_m2 <= #{areaMax}


                AND manage_cost <= #{manageCostMax}


        ORDER BY embedding <-> CAST(#{embeddingLiteral} AS vector(1536))
        LIMIT #{topK}

        SELECT
            item_id AS itemId, title, sales_type, service_type,
	        local1, local2, local3, jibun_address      AS jibunAddress,
	        deposit, rent, manage_cost AS manageCost, manage_not_includes AS manageNotIncludes,
	        area_m2 AS areaM2, area_contract_m2 AS areaContractM2,
	        floor_level AS floorLevel, all_floors AS allFloors,
	        lat, lng, options,
            subway, nb_distribution AS nbDistribution, nb_amenity AS nbAmenity, nb_poi, item_image
        FROM property


                AND local1 = #{local1}


                AND local2 = #{local2}


                AND local3 = #{local3}



            AND item_id NOT IN

                #{id}



        ORDER BY embedding <-> CAST(#{embeddingLiteral} AS vector(1536))
        LIMIT #{regionLimit}

SELECT item_id AS itemId, title, sales_type, service_type, local1, local2, local3, jibun_address AS jibunAddress, deposit, rent, manage_cost AS manageCost, manage_not_includes AS manageNotIncludes, area_m2 AS areaM2, area_contract_m2 AS areaContractM2, floor_level AS floorLevel, all_floors AS allFloors, lat, lng, options, subway, nb_distribution AS nbDistribution, nb_amenity AS nbAmenity, nb_poi, item_image FROM property
AND ( CAST(item_id AS TEXT) = #{keyword} OR title ILIKE CONCAT('%', #{keyword}, '%') OR local1 ILIKE CONCAT('%', #{keyword}, '%') OR local2 ILIKE CONCAT('%', #{keyword}, '%') OR local3 ILIKE CONCAT('%', #{keyword}, '%') OR jibun_address ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY item_id DESC LIMIT #{topK}
